import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { configuracaoEmpresa, colaboradores as mockColaboradores } from '../data/mockData';

type ViewMode = 'login' | 'register' | 'confirm' | 'forgot';

const Login: React.FC = () => {
  const navigate = useNavigate();
  const { 
    setIsAuthenticated, setColaboradores, setEmpresa, setUser, 
    setIsConfigured, setEmpresas, setEmpresaId 
  } = useContext(AppContext);

  const [mode, setMode] = useState<ViewMode>('login');
  const [email, setEmail] = useState('admin@salya.com');
  const [password, setPassword] = useState('admin123');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');
  const [confirmCode, setConfirmCode] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [errorString, setErrorString] = useState('');

  const executeLogin = (userEmail: string, userName: string) => {
    setIsAuthenticated(true);
    setUser({ email: userEmail, name: userName });

    if (userEmail === 'admin@salya.com') {
      const empresaComId = { ...configuracaoEmpresa, id: 1 };
      setEmpresas([empresaComId]);
      setEmpresaId(1);
      setEmpresa(empresaComId);
      setColaboradores(mockColaboradores.map(c => ({ ...c, empresaId: 1 })));
      setIsConfigured(true);
      navigate('/processamento');
    } else {
      setEmpresas([]);
      setEmpresaId(null);
      setEmpresa(null);
      setColaboradores([]);
      setIsConfigured(false);
      navigate('/configuracoes');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorString('');
    if (email && password) {
      executeLogin(email, 'Administrador');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorString('');
    if (name && email && password) {
      setMode('confirm');
    }
  };

  const handleConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (confirmCode) {
      setMode('login');
      setEmail('');
      setPassword('');
      setName('');
      setConfirmPassword('');
      setConfirmCode('');
    }
  };

  const handleForgotPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setMode('login');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-50 dark:bg-slate-950">
      <div className="flex h-auto w-full max-w-[1000px] bg-white dark:bg-slate-900 rounded-[32px] shadow-2xl overflow-hidden border border-slate-100 dark:border-slate-800">

        {/* Left Side - Simplified Premium Branding */}
        <div className="hidden md:flex md:w-1/2 relative bg-primary items-center justify-center p-12 overflow-hidden">
          <div className="absolute inset-0 opacity-10 bg-cover bg-center" style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800")' }}></div>
          <div className="absolute inset-0 bg-gradient-to-br from-primary via-primary/95 to-slate-900/60"></div>

          <div className="relative z-10 flex flex-col items-center gap-6 text-white">
            <img src="/logo.png" alt="SALYA Logo" className="w-24 h-24 object-contain bg-white/10 p-4 rounded-2xl shadow-xl backdrop-blur-sm" />
            <div className="text-center">
              <h1 className="text-4xl font-black tracking-tighter uppercase mb-2">SALYA</h1>
              <p className="text-[10px] font-black uppercase tracking-[8px] opacity-60">Smarter Payroll</p>
            </div>
          </div>
        </div>

        {/* Right Side - Forms */}
        <div className="w-full md:w-1/2 p-10 md:p-14 flex flex-col justify-center">
          <div className="md:hidden flex flex-col items-center gap-2 mb-10">
            <img src="/logo.png" alt="SALYA Logo" className="w-12 h-12 object-contain" />
            <h1 className="text-xl font-black tracking-tight text-primary">SALYA</h1>
          </div>

          {mode === 'login' && (
            <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="mb-8">
                <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Entrar no SALYA</h2>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest">Acesso ao Painel de Gestão</p>
              </div>

              <form className="space-y-5" onSubmit={handleLogin}>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Utilizador / E-mail</label>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white transition-all"
                    required
                  />
                </div>

                <div className="space-y-1.5">
                  <div className="flex justify-between items-center">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Palavra-passe</label>
                    <button type="button" onClick={() => setMode('forgot')} className="text-[9px] font-black text-primary uppercase tracking-widest hover:underline">Recuperar?</button>
                  </div>
                  <input
                    type={showPassword ? 'text' : 'password'}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white transition-all"
                    required
                  />
                </div>

                <button type="submit" className="w-full bg-primary hover:bg-primary/95 text-white font-black py-5 rounded-2xl shadow-xl shadow-primary/20 transition-all flex items-center justify-center gap-3 uppercase tracking-[4px] text-xs">
                  Entrar no Sistema
                </button>

                <p className="mt-8 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  Novo aqui? <button type="button" onClick={() => setMode('register')} className="text-primary hover:underline">Criar Conta</button>
                </p>
              </form>
            </div>
          )}

          {mode === 'register' && (
            <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="mb-8 text-center sm:text-left">
                <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Criar Nova Conta</h2>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest">Registe-se em poucos segundos</p>
              </div>

              <form className="space-y-4" onSubmit={handleRegister}>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Administrador / Responsável</label><input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail Corporativo</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Definir Senha</label><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>

                <button type="submit" className="w-full bg-primary hover:bg-primary/95 text-white font-black py-5 mt-4 rounded-2xl shadow-xl shadow-primary/20 transition-all uppercase tracking-[4px] text-xs">
                  Registar Agora
                </button>

                <button type="button" onClick={() => setMode('login')} className="w-full text-center text-[10px] font-black text-slate-400 uppercase tracking-widest mt-4">Já tem conta? Login</button>
              </form>
            </div>
          )}

          {mode === 'confirm' && (
            <div className="animate-in zoom-in-95 duration-300">
              <div className="text-center mb-8">
                 <h2 className="text-xl font-black uppercase text-slate-800 dark:text-white tracking-tight">Verificação</h2>
                 <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-widest">Código enviado para o e-mail</p>
              </div>
              <form className="space-y-6" onSubmit={handleConfirm}>
                <input
                  type="text"
                  maxLength={6}
                  value={confirmCode}
                  onChange={(e) => setConfirmCode(e.target.value)}
                  className="w-full text-center text-4xl font-black tracking-[12px] py-6 bg-slate-50 dark:bg-slate-800 rounded-3xl outline-none focus:ring-2 focus:ring-primary dark:text-white font-mono"
                  placeholder="000000"
                  required
                />
                <button type="submit" className="w-full bg-primary hover:bg-primary/95 text-white font-black py-5 rounded-2xl shadow-xl shadow-primary/20 uppercase tracking-[4px] text-xs">
                  Validar Código
                </button>
              </form>
            </div>
          )}

          {mode === 'forgot' && (
            <div className="animate-in fade-in duration-300">
               <div className="text-center mb-8">
                <h2 className="text-xl font-black uppercase text-slate-800 dark:text-white tracking-tight">Recuperar</h2>
                <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-widest">Introduza o seu e-mail de acesso</p>
              </div>
              <form className="space-y-6" onSubmit={handleForgotPassword}>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
                <button type="submit" className="w-full bg-primary hover:bg-primary/95 text-white font-black py-5 rounded-2xl shadow-xl shadow-primary/20 uppercase tracking-[4px] text-xs">Enviar Link</button>
                <button type="button" onClick={() => setMode('login')} className="w-full text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">Voltar</button>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;
